// NetworkModule.java
import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class NetworkModule {
    private static final String BASE_URL_DEV = "https://dev.api.example.com/";
    private static final String BASE_URL_STAGING = "https://staging.api.example.com/";
    private static final String BASE_URL_PROD = "https://api.example.com/";

    public static ApiService createApiService(Environment environment) {
        String baseUrl;
        switch (environment) {
            case DEVELOPMENT:
                baseUrl = BASE_URL_DEV;
                break;
            case STAGING:
                baseUrl = BASE_URL_STAGING;
                break;
            case PRODUCTION:
            default:
                baseUrl = BASE_URL_PROD;
                break;
        }

        OkHttpClient client = new OkHttpClient.Builder()
                .build();

        Retrofit retrofit = new Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();

        return retrofit.create(ApiService.class);
    }

    public enum Environment {
        DEVELOPMENT,
        STAGING,
        PRODUCTION
    }
}

// MainActivity.java
import android.os.Bundle;
import android.util.Log;
import androidx.appcompat.app.AppCompatActivity;
import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import java.util.List;

public class MainActivity extends AppCompatActivity {
    private static final String TAG = "MainActivity";

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        ApiService apiService = NetworkModule.createApiService(NetworkModule.Environment.PRODUCTION);
        apiService.getUsers().enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    for (User user : response.body()) {
                        Log.d(TAG, "User: " + user.getName());
                    }
                } else {
                    Log.e(TAG, "Response error: " + response.code());
                }
            }

            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                Log.e(TAG, "Network error: " + t.getMessage());
            }
        });
    }
}